   \"id@\": \"/Comment/toId\",\n            \"id>\": 0\n        }\n    },\n    \"@explain\": true\n}\n/*\n 这是一个 3.3.0, 3.8.6-4.0.0 都发现存在的 bug，\n 事实上也是自从支持自连接（副表 Comment AS `to`）以来就存在。\n 原因是对副表生成的 SQL 里表名和主表表名一样，导致 \n AbstractSQLExecutor.onPutColumn 中 299 行\n item = onPutColumn(config, rs, rsmd, index, item, i, config.isExplain() == false && hasJoin && i >= viceColumnStart ? childMap : null);\n 488 行 if 走了第一个分支（应该走 else 来把副表的值存进 childMap）\n finalTable = table;\n 从而使 JOIN 查出来的主副表全部字段都在 521 行\n finalTable.put(lable, getValue(config, rs, rsmd, tablePosition, table, columnIndex, lable, childMap));\n 由于主副表有相同字段，导致后面 put 的副表字段替代了前面 put 的主表同名字段。\n \n 除了以上折中方案，还可以判断 AS 的副表别名来做区分，put 进 childMap。\n*/',NULL,NULL,NULL,'','2020-03-13 15:37:03',NULL,NULL),(1584117747580,0,0,2000,NULL,0,3,NULL,NULL,'全局默认字段失效',NULL,'POST','JSON','/login','{\n    \"type\": 0,\n    \"phone\": \"13000082001\",\n    \"password\": \"123456\",\n    \"version\": 1,\n    \"remember\": false,\n    \"format\": true,  //失效\n    \"defaults\": {  //失效\n        \"format\": true,\n        \"@explain\": true,\n        \"@database\": \"POSTGRESQL\",\n        \"@schema\": \"sys\"\n    }\n}',NULL,NULL,NULL,'','2020-03-13 16:42:27',NULL,NULL),(1584118278602,0,0,2000,NULL,0,3,NULL,NULL,'SIDE JOIN 实现可能有误','SELECT','POST','JSON','/get','{\n    \"[]\": {\n        \"join\": \"^/User/id@\",\n        \"Comment\": {\n            \"momentId\": 12\n        },\n        \"User\": {\n            \"id@\": \"/Comment/toId\",\n            \"sex\": 0\n        }\n    },\n    \"@explain\": true\n}\n/*\n SIDE JOIN 实现可能有误，并且性能不大好。\n Comment 的条件 A: momentId=12\n User 的条件 B: sex=0\n 理论上 NOT(A AND B) 等价于(A AND NOT B) OR (B AND NOT A) \n 目前使用的是后者，当我想要改成前者，分别用对应的 SQL 放数据库执行，\n 发现结果集不一样！\n SELECT `Comment`.*, `User`.* FROM `sys`.`Comment` AS `Comment` INNER JOIN `sys`.`apijson_user` AS `User` ON `User`.`id` = `Comment`.`toId` WHERE ( NOT ( `Comment`.`momentId` = 12 AND `User`.`sex` = 0 ) ) LIMIT 10 OFFSET 0\n SELECT `Comment`.*, `User`.* FROM `sys`.`Comment` AS `Comment` INNER JOIN `sys`.`apijson_user` AS `User` ON `User`.`id` = `Comment`.`toId` WHERE ( ( ( (`Comment`.`momentId` = 12) ) AND NOT ( ( (`User`.`sex` = 0) ) ) ) OR ( ( (`User`.`sex` = 0) ) AND NOT ( ( (`Comment`.`momentId` = 12) ) ) ) ) LIMIT 10 OFFSET 0\n*/',NULL,NULL,NULL,'','2020-03-13 16:51:18',NULL,NULL),(1584120971519,0,0,2020,NULL,0,3,NULL,NULL,'新增 WITH AS','SELECT','POST','JSON','/get','{   //看看关注的人最近有什么动态（分享、评论）\n    \"sql@\": {\n        \"with\": true,  //生成 WITH(SELECT id ...) AS `sql`\n        \"from\": \"User\",\n        \"User\": {\n            \"@column\": \"id\",\n            \"@role\": \"CONTACT\"\n        }\n    },\n    \"Moment[]\": {\n        \"Moment\": {\n            \"userId{}@\": \"sql\",\n            \"@order\": \"date-\"\n        }\n    },\n    \"Comment[]\": {\n        \"Comment\": {\n            \"userId{}@\": \"sql\",\n            \"@order\": \"date-\"\n        }\n    },\n    \"@explain\": true\n}',NULL,NULL,NULL,'','2020-03-13 17:36:11',NULL,NULL),(1584120990337,0,0,2020,NULL,0,3,NULL,NULL,'新增 UNION','SELECT','POST','JSON','/get','{\n    \"[]\": {\n        \"User\": {\n            \"name~\": \"a\",\n            \"tag~\": \"a\",\n            \"@combine\": \"name~,tag~\",    \n            \"@union\": 1  //将 @combine 中的 N 个 OR 连接字段用 UNION 替换，原本一条 SQL 需要拆分成 N 条 SQL 来 UNION \n        }\n    },\n    \"@explain\": true\n}',NULL,NULL,NULL,'','2020-03-13 17:36:30',NULL,NULL),(1584121026469,0,0,2020,NULL,0,3,NULL,NULL,'新增分布式执行','SELECT','POST','JSON','/get','{\n    \"User\": {\n        \"@url\": \"http://apijson.cn:8080/get\"  //转发给其它服务器执行\n    },\n    \"[]\": {\n        \"Comment\": {\n            \"userId@\": \"User/id\"\n        }\n    },\n    \"@explain\": true\n}',NULL,NULL,NULL,'','2020-03-13 17:37:06',NULL,NULL),(1589859330200,0,0,1589859275450,NULL,1589859275450,3,NULL,NULL,'login',NULL,'POST','JSON','/login','{\n    \"type\": 0,\n    \"phone\": \"13525569073\",\n    \"password\": \"123456\",\n    \"version\": 1,\n   